@namespace Lumeo
@typeparam TItem

<div class="@CssClass" @attributes="AdditionalAttributes">
    @foreach (var (item, index) in _items.Select((x, i) => (x, i)))
    {
        <div class="@GetItemClass(index)"
             draggable="@(!Disabled ? "true" : "false")"
             @ondragstart="() => OnDragStart(index)"
             @ondragover:preventDefault="true"
             @ondragover="() => OnDragOver(index)"
             @ondragleave="OnDragLeave"
             @ondrop="() => OnDrop(index)"
             @ondragend="OnDragEnd">
            @if (Handle && !Disabled)
            {
                <div class="flex-shrink-0 cursor-grab active:cursor-grabbing text-muted-foreground hover:text-foreground mr-2 flex items-center">
                    <Blazicon Svg="Lucide.GripVertical" class="h-4 w-4" />
                </div>
            }
            <div class="flex-1 min-w-0">
                @if (ItemTemplate is not null)
                {
                    @ItemTemplate(item)
                }
            </div>
        </div>
    }
</div>

@code {
    [Parameter] public List<TItem> Items { get; set; } = [];
    [Parameter] public EventCallback<List<TItem>> ItemsChanged { get; set; }
    [Parameter] public RenderFragment<TItem>? ItemTemplate { get; set; }
    [Parameter] public bool Handle { get; set; } = true;
    [Parameter] public bool Disabled { get; set; }
    [Parameter] public string? Group { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private List<TItem> _items = [];
    private int _dragFromIndex = -1;
    private int _dragOverIndex = -1;

    protected override void OnParametersSet()
    {
        _items = Items.ToList();
    }

    private string CssClass => $"flex flex-col gap-1 {Class}".Trim();

    private string GetItemClass(int index)
    {
        var classes = "flex items-center rounded-md border border-border/40 bg-card px-3 py-2 transition-all";
        if (index == _dragFromIndex)
            classes += " opacity-50";
        if (index == _dragOverIndex && index != _dragFromIndex)
            classes += " border-primary border-2";
        if (!Handle && !Disabled)
            classes += " cursor-grab active:cursor-grabbing";
        return classes;
    }

    private void OnDragStart(int index)
    {
        _dragFromIndex = index;
    }

    private void OnDragOver(int index)
    {
        _dragOverIndex = index;
    }

    private void OnDragLeave()
    {
        _dragOverIndex = -1;
    }

    private async Task OnDrop(int toIndex)
    {
        if (_dragFromIndex < 0 || _dragFromIndex == toIndex)
        {
            _dragFromIndex = -1;
            _dragOverIndex = -1;
            return;
        }

        var item = _items[_dragFromIndex];
        _items.RemoveAt(_dragFromIndex);
        _items.Insert(toIndex, item);

        _dragFromIndex = -1;
        _dragOverIndex = -1;

        await ItemsChanged.InvokeAsync(_items.ToList());
    }

    private void OnDragEnd()
    {
        _dragFromIndex = -1;
        _dragOverIndex = -1;
    }
}
